1	import { ThreadId } from "@t3tools/contracts";
2	import {
3	  Outlet,
4	  createRootRouteWithContext,
5	  type ErrorComponentProps,
6	  useNavigate,
7	  useRouterState,
8	} from "@tanstack/react-router";
9	import { useEffect, useRef } from "react";
10	import { QueryClient, useQueryClient } from "@tanstack/react-query";
11	
12	import { APP_DISPLAY_NAME } from "../branding";
13	import { Button } from "../components/ui/button";
14	import { AnchoredToastProvider, ToastProvider, toastManager } from "../components/ui/toast";
15	import { serverConfigQueryOptions, serverQueryKeys } from "../lib/serverReactQuery";
16	import { readNativeApi } from "../nativeApi";
17	import { useComposerDraftStore } from "../composerDraftStore";
18	import { useStore } from "../store";
19	import { useTerminalStateStore } from "../terminalStateStore";
20	import { preferredTerminalEditor } from "../terminal-links";
21	import { terminalRunningSubprocessFromEvent } from "../terminalActivity";
22	import { onServerConfigUpdated, onServerWelcome } from "../wsNativeApi";
23	import { providerQueryKeys } from "../lib/providerReactQuery";
24	import { collectActiveTerminalThreadIds } from "../lib/terminalStateCleanup";
25	
26	export const Route = createRootRouteWithContext<{
27	  queryClient: QueryClient;
28	}>()({
29	  component: RootRouteView,
30	  errorComponent: RootRouteErrorView,
31	  head: () => ({
32	    meta: [{ name: "title", content: APP_DISPLAY_NAME }],
33	  }),
34	});
35	
36	function RootRouteView() {
37	  if (!readNativeApi()) {
38	    return (
39	      <div className="flex h-screen flex-col bg-background text-foreground">
40	        <div className="flex flex-1 items-center justify-center">
41	          <p className="text-sm text-muted-foreground">
42	            Connecting to {APP_DISPLAY_NAME} server...
43	          </p>
44	        </div>
45	      </div>
46	    );
47	  }
48	
49	  return (
50	    <ToastProvider>
51	      <AnchoredToastProvider>
52	        <EventRouter />
53	        <DesktopProjectBootstrap />
54	        <Outlet />
55	      </AnchoredToastProvider>
56	    </ToastProvider>
57	  );
58	}
59	
60	function RootRouteErrorView({ error, reset }: ErrorComponentProps) {
61	  const message = errorMessage(error);
62	  const details = errorDetails(error);
63	
64	  return (
65	    <div className="relative flex min-h-screen items-center justify-center overflow-hidden bg-background px-4 py-10 text-foreground sm:px-6">
66	      <div className="pointer-events-none absolute inset-0 opacity-80">
67	        <div className="absolute inset-x-0 top-0 h-44 bg-[radial-gradient(44rem_16rem_at_top,color-mix(in_srgb,var(--color-red-500)_16%,transparent),transparent)]" />
68	        <div className="absolute inset-0 bg-[linear-gradient(145deg,color-mix(in_srgb,var(--background)_90%,var(--color-black))_0%,var(--background)_55%)]" />
69	      </div>
70	
71	      <section className="relative w-full max-w-xl rounded-2xl border border-border/80 bg-card/90 p-6 shadow-2xl shadow-black/20 backdrop-blur-md sm:p-8">
72	        <p className="text-[11px] font-semibold tracking-[0.18em] text-muted-foreground uppercase">
73	          {APP_DISPLAY_NAME}
74	        </p>
75	        <h1 className="mt-3 text-2xl font-semibold tracking-tight sm:text-3xl">
76	          Something went wrong.
77	        </h1>
78	        <p className="mt-2 text-sm leading-relaxed text-muted-foreground">{message}</p>
79	
80	        <div className="mt-5 flex flex-wrap gap-2">
81	          <Button size="sm" onClick={() => reset()}>
82	            Try again
83	          </Button>
84	          <Button size="sm" variant="outline" onClick={() => window.location.reload()}>
85	            Reload app
86	          </Button>
87	        </div>
88	
89	        <details className="group mt-5 overflow-hidden rounded-lg border border-border/70 bg-background/55">
90	          <summary className="cursor-pointer list-none px-3 py-2 text-xs font-medium text-muted-foreground">
91	            <span className="group-open:hidden">Show error details</span>
92	            <span className="hidden group-open:inline">Hide error details</span>
93	          </summary>
94	          <pre className="max-h-56 overflow-auto border-t border-border/70 bg-background/80 px-3 py-2 text-xs text-foreground/85">
95	            {details}
96	          </pre>
97	        </details>
98	      </section>
99	    </div>
100	  );
101	}
102	
103	function errorMessage(error: unknown): string {
104	  if (error instanceof Error && error.message.trim().length > 0) {
105	    return error.message;
106	  }
107	
108	  if (typeof error === "string" && error.trim().length > 0) {
109	    return error;
110	  }
111	
112	  return "An unexpected router error occurred.";
113	}
114	
115	function errorDetails(error: unknown): string {
116	  if (error instanceof Error) {
117	    return error.stack ?? error.message;
118	  }
119	
120	  if (typeof error === "string") {
121	    return error;
122	  }
123	
124	  try {
125	    return JSON.stringify(error, null, 2);
126	  } catch {
127	    return "No additional error details are available.";
128	  }
129	}
130	
131	function EventRouter() {
132	  const syncServerReadModel = useStore((store) => store.syncServerReadModel);
133	  const setProjectExpanded = useStore((store) => store.setProjectExpanded);
134	  const removeOrphanedTerminalStates = useTerminalStateStore(
135	    (store) => store.removeOrphanedTerminalStates,
136	  );
137	  const queryClient = useQueryClient();
138	  const navigate = useNavigate();
139	  const pathname = useRouterState({ select: (state) => state.location.pathname });
140	  const pathnameRef = useRef(pathname);
141	  const lastConfigIssuesSignatureRef = useRef<string | null>(null);
142	  const handledBootstrapThreadIdRef = useRef<string | null>(null);
143	
144	  pathnameRef.current = pathname;
145	
146	  useEffect(() => {
147	    const api = readNativeApi();
148	    if (!api) return;
149	    let disposed = false;
150	    let latestSequence = 0;
151	    let syncing = false;
152	    let pending = false;
153	
154	    const flushSnapshotSync = async (): Promise<void> => {
155	      const snapshot = await api.orchestration.getSnapshot();
156	      if (disposed) return;
157	      latestSequence = Math.max(latestSequence, snapshot.snapshotSequence);
158	      syncServerReadModel(snapshot);
159	      const draftThreadIds = Object.keys(
160	        useComposerDraftStore.getState().draftThreadsByThreadId,
161	      ) as ThreadId[];
162	      const activeThreadIds = collectActiveTerminalThreadIds({
163	        snapshotThreads: snapshot.threads,
164	        draftThreadIds,
165	      });
166	      removeOrphanedTerminalStates(activeThreadIds);
167	      if (pending) {
168	        pending = false;
169	        await flushSnapshotSync();
170	      }
171	    };
172	
173	    const syncSnapshot = async () => {
174	      if (syncing) {
175	        pending = true;
176	        return;
177	      }
178	      syncing = true;
179	      pending = false;
180	      try {
181	        await flushSnapshotSync();
182	      } catch {
183	        // Keep prior state and wait for next domain event to trigger a resync.
184	      }
185	      syncing = false;
186	    };
187	
188	    void syncSnapshot().catch(() => undefined);
189	
190	    const unsubDomainEvent = api.orchestration.onDomainEvent((event) => {
191	      if (event.sequence <= latestSequence) {
192	        return;
193	      }
194	      latestSequence = event.sequence;
195	      if (event.type === "thread.turn-diff-completed" || event.type === "thread.reverted") {
196	        void queryClient.invalidateQueries({ queryKey: providerQueryKeys.all });
197	      }
