48	  const theme = getStored();
49	  const systemDark = theme === "system" ? getSystemDark() : false;
50	
51	  if (lastSnapshot && lastSnapshot.theme === theme && lastSnapshot.systemDark === systemDark) {
52	    return lastSnapshot;
53	  }
54	
55	  lastSnapshot = { theme, systemDark };
56	  return lastSnapshot;
57	}
