  mutedForeground: string;
  accent: string;
  accentForeground: string;
  destructive: string;
  destructiveForeground: string;
  border: string;
  input: string;
  ring: string;
  // Extended surfaces
  sidebar: string;
  sidebarForeground: string;
  sidebarBorder: string;
  editor: string;
  editorForeground: string;
  terminal: string;
  terminalForeground: string;
  statusBar: string;
  statusBarForeground: string;
}

export interface ThemeDefinition {
  id: ThemeId;
  label: string;
  isDark: boolean;
  tokens: ThemeTokens;
}
```

**CSS custom property values for all three themes:**

