import { Schema } from "effect";

export const BUILT_IN_THEME_IDS = ["t3-dark", "t3-light", "t3-midnight"] as const;
export const ThemeId = Schema.Literals(BUILT_IN_THEME_IDS);
export type ThemeId = typeof ThemeId.Type;

export interface ThemeColorTokens {
  background: string;
  foreground: string;
  accent: string;
  sidebar: string;
  editor: string;
  terminal: string;
  statusBar: string;
}

export interface ThemeDefinition {
  id: ThemeId;
  name: string;
  colorScheme: "light" | "dark";
  tokens: ThemeColorTokens;
}

