import type { ThemeDefinition } from "@t3tools/contracts";
import { useTheme } from "../hooks/useTheme";
import { BUILT_IN_THEMES } from "../themes";

function ThemeSwatch({ theme }: { theme: ThemeDefinition }) {
  return (
    <div className="flex h-8 w-full overflow-hidden rounded-md" aria-hidden="true">
      <div className="w-1/4 shrink-0" style={{ background: theme.tokens.sidebar }} />
      <div className="flex-1" style={{ background: theme.tokens.editor }} />
      <div className="w-1/6 shrink-0" style={{ background: theme.tokens.statusBar }} />
      <div className="w-1/6 shrink-0" style={{ background: theme.tokens.accent }} />
    </div>
  );
}

export function ThemeSelector() {
  const { themeId, setTheme } = useTheme();

  return (
    <div className="grid grid-cols-1 gap-2 sm:grid-cols-3" role="radiogroup" aria-label="Color theme">
      {BUILT_IN_THEMES.map((theme) => {
        const selected = themeId === theme.id;
        return (
          <button
            key={theme.id}
            type="button"
            role="radio"
            aria-checked={selected}
            className={`flex flex-col gap-2 rounded-lg border px-3 py-2.5 text-left transition-colors ${
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent"
            }`}
            onClick={() => setTheme(theme.id)}
          >
            <ThemeSwatch theme={theme} />
            <div className="flex items-center justify-between gap-2">
              <span className="text-xs font-medium">{theme.name}</span>
              {selected ? (
                <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                  Active
                </span>
              ) : null}
            </div>
          </button>
        );
      })}
    </div>
  );
}

